// components/Contact.js
import React, { useState } from 'react';
import emailjs from '@emailjs/browser';

const Contact = () => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    subject: '',
    message: ''
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitStatus, setSubmitStatus] = useState(null);

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);
    setSubmitStatus(null);

    try {
      // EmailJS configuration - Get these from your .env file
      const serviceId = process.env.REACT_APP_EMAILJS_SERVICE_ID;
      const templateId = process.env.REACT_APP_EMAILJS_TEMPLATE_ID;
      const publicKey = process.env.REACT_APP_EMAILJS_PUBLIC_KEY;

      // Check if credentials are configured
      if (!serviceId || !templateId || !publicKey ||
          serviceId === 'service_test123' ||
          templateId === 'template_test123' ||
          publicKey === 'test_public_key_123') {
        throw new Error('EmailJS not configured. Please set up your EmailJS account and update the .env file with real credentials.');
      }

      const templateParams = {
        from_name: formData.name,
        from_email: formData.email,
        subject: formData.subject,
        message: formData.message,
        to_email: 'anushakprn@gmail.com', // Your email address
      };

      console.log('Sending email with params:', templateParams);

      await emailjs.send(serviceId, templateId, templateParams, publicKey);

      setSubmitStatus('success');
      setFormData({
        name: '',
        email: '',
        subject: '',
        message: ''
      });
    } catch (error) {
      console.error('Email send failed:', error);
      setSubmitStatus('error');

      // Show specific error message
      if (error.message.includes('EmailJS not configured')) {
        alert('EmailJS is not configured yet. Please follow the setup instructions in the README.md file.');
      }
    } finally {
      setIsSubmitting(false);
    }
  };

  const contactInfo = [
    {
      icon: "fas fa-envelope",
      title: "Email",
      value: "anushakprn@gmail.com",
      link: "mailto:anushakprn@gmail.com"
    },
    {
      icon: "fas fa-phone",
      title: "Phone",
      value: "+91 8179377979",
      link: "tel:+918179377979"
    },
    {
      icon: "fas fa-map-marker-alt",
      title: "Location",
      value: "Tirupati, India",
      link: "#"
    }
  ];

  const socialLinks = [
    {
      icon: "fab fa-linkedin",
      title: "LinkedIn",
      link: "https://www.linkedin.com/in/anusha-kothapalli-b905b7291/",
      color: "#0077B5"
    },
    {
      icon: "fab fa-github",
      title: "GitHub",
      link: "https://github.com/anushakprn",
      color: "#333"
    },
    {
      icon: "fas fa-code",
      title: "LeetCode",
      link: "https://leetcode.com/u/anushakprn/",
      color: "#FFA116"
    }
  ];

  return (
    <div className="section contact-section">
      <div className="section-header">
        <h2 className="section-title">Get In Touch</h2>
        <div className="section-divider"></div>
        <p className="section-subtitle">I'm always open to discussing new opportunities and innovative ideas</p>
      </div>
      
      <div className="contact-container">
        <div className="contact-info">
          <h3 className="contact-heading">Let's Connect!</h3>
          <p className="contact-description">
            I'm currently looking for full-time opportunities in Data Science, Machine Learning, 
            or Full Stack Development. Feel free to reach out if you want to collaborate on 
            interesting projects or discuss potential opportunities.
          </p>
          
          <div className="contact-details">
            {contactInfo.map((info, index) => (
              <a key={index} href={info.link} className="contact-detail">
                <div className="detail-icon">
                  <i className={info.icon}></i>
                </div>
                <div className="detail-content">
                  <h4>{info.title}</h4>
                  <p>{info.value}</p>
                </div>
              </a>
            ))}
          </div>
          
          <div className="contact-social">
            <h4>Connect with me:</h4>
            <div className="social-links">
              {socialLinks.map((social, index) => (
                <a 
                  key={index} 
                  href={social.link} 
                  target="_blank" 
                  rel="noopener noreferrer"
                  className="social-icon"
                  style={{ backgroundColor: social.color }}
                >
                  <i className={social.icon}></i>
                  <span>{social.title}</span>
                </a>
              ))}
            </div>
          </div>
        </div>
        
        <div className="contact-form-container">
          <h3 className="form-title">Send me a message</h3>
          <form onSubmit={handleSubmit} className="contact-form">
            <div className="form-group">
              <input
                type="text"
                name="name"
                placeholder="Your Name"
                value={formData.name}
                onChange={handleChange}
                required
              />
            </div>
            <div className="form-group">
              <input
                type="email"
                name="email"
                placeholder="Your Email"
                value={formData.email}
                onChange={handleChange}
                required
              />
            </div>
            <div className="form-group">
              <input
                type="text"
                name="subject"
                placeholder="Subject"
                value={formData.subject}
                onChange={handleChange}
                required
              />
            </div>
            <div className="form-group">
              <textarea
                name="message"
                placeholder="Your Message"
                rows="5"
                value={formData.message}
                onChange={handleChange}
                required
              ></textarea>
            </div>
            <button type="submit" className="submit-btn" disabled={isSubmitting}>
              <i className="fas fa-paper-plane"></i> {isSubmitting ? 'Sending...' : 'Send Message'}
            </button>
          </form>
          
          {submitStatus === 'success' && (
            <div className="success-message" style={{ 
              color: '#28a745', 
              marginTop: '15px', 
              padding: '10px', 
              border: '1px solid #28a745', 
              borderRadius: '5px',
              backgroundColor: '#d4edda'
            }}>
              <i className="fas fa-check-circle"></i> Message sent successfully! I'll get back to you soon.
            </div>
          )}
          
          {submitStatus === 'error' && (
            <div className="error-message" style={{ 
              color: '#dc3545', 
              marginTop: '15px', 
              padding: '10px', 
              border: '1px solid #dc3545', 
              borderRadius: '5px',
              backgroundColor: '#f8d7da'
            }}>
              <i className="fas fa-exclamation-circle"></i> Failed to send message. Please try again or contact me directly.
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Contact;
